// ============================================================
// SAME AS YOUR ORIGINAL - just adding shot_num + position meta
// ============================================================
const data = $items("Merge for concept and Avatar Data", 0, 0)[0].json;

const avatarNames = data["Avatar Names"];
const urls = data["Reference URLs"];
const masterShotUrl = $items("Upload file", 0, 0)[0].json.webContentLink;

const mapping = {};
const image_urls = [masterShotUrl];

avatarNames.forEach((name, index) => {
  const imageIndex = index + 1;
  mapping[name] = `<image:${imageIndex}>`;
  image_urls.push(urls[index]);
});

const storyShot = $json.StoryShots.framePrompt || "";
const clothing   = $json.ClothingDetails || "";

let combinedPrompt = `${storyShot}`;
avatarNames.forEach((name, index) => {
  const imageIndex = index + 1;
  combinedPrompt = combinedPrompt
    .replaceAll(`<<${name}>>`, `<image:${imageIndex}>`)
    .replaceAll(`<<${name.replace(/[0-9]/g, "")}>>`, `<image:${imageIndex}>`);
});

const shot_num = $itemIndex + 1; // 1-based

return {
  json: {
    ...$json,

    // === CRITICAL IDENTITY FIELDS — survive the entire pipeline ===
    shot_num,                          // e.g. 1, 2, 3
    shot_position: $itemIndex,         // 0-based, for $position references
    total_shots: $items().length,      // know when we're done
    reelNumber: $('2. Extract Reel Data').item.json.reelNumber,
    reelReviewId: $('Create Review FolderID').item.json.ReelReviewId,

    // === PROMPT DATA ===
    shot_prompt: storyShot,
    kling_prompt: combinedPrompt,
    image_urls,
    mapping
  }
};

// ============================================================
// CRITICAL BRIDGE: Attach response_url + ALL shot identity
// fields directly onto the item BEFORE entering the poll loop.
// This means the loop never needs to reach back to a parent
// node — everything travels with the item.
// ============================================================
const promptMeta = $('create generate model prompts').item.json;
const apiResponse = $input.item.json;

if (!apiResponse.request_id && !apiResponse.response_url) {
  // fal.ai didn't give us a handle — mark for dead-letter
  return [{
    json: {
      ...promptMeta,
      __fal_error: true,
      __fal_error_msg: 'fal.ai returned no request_id or response_url',
      __fal_raw: apiResponse
    }
  }];
}

return [{
  json: {
    // === Shot identity (from prompt node) ===
    shot_num:      promptMeta.shot_num,
    shot_position: promptMeta.shot_position,
    total_shots:   promptMeta.total_shots,
    reelNumber:    promptMeta.reelNumber,
    reelReviewId:  promptMeta.reelReviewId,
    kling_prompt:  promptMeta.kling_prompt,
    shot_prompt:   promptMeta.shot_prompt,
    image_urls:    promptMeta.image_urls,

    // === fal.ai polling handles ===
    request_id:   apiResponse.request_id,
    status_url:   apiResponse.status_url  || `https://queue.fal.run/fal-ai/nano-banana-2/requests/${apiResponse.request_id}/status`,
    response_url: apiResponse.response_url || `https://queue.fal.run/fal-ai/nano-banana-2/requests/${apiResponse.request_id}`,
    cancel_url:   apiResponse.cancel_url,

    // === Retry guards ===
    __retryCount: 0,
    __maxRetries: 24,         // 24 × 15s = 6 minutes max per shot
    __retryDelaySec: 15,
    __fal_error: false
  }
}];

// Re-merge poll result with the shot context that was on the item
// entering the loop. The status API only returns {status, ...}
// so we must carry our identity forward manually.
const loopItem   = $('Loop Over Items1').item.json;   // has all our __fields
const pollResult = $input.item.json;                   // has status from fal

return [{
  json: {
    // Identity always wins over poll result
    shot_num:       loopItem.shot_num,
    shot_position:  loopItem.shot_position,
    total_shots:    loopItem.total_shots,
    reelNumber:     loopItem.reelNumber,
    reelReviewId:   loopItem.reelReviewId,
    kling_prompt:   loopItem.kling_prompt,
    shot_prompt:    loopItem.shot_prompt,
    image_urls:     loopItem.image_urls,
    request_id:     loopItem.request_id,
    status_url:     loopItem.status_url,
    response_url:   loopItem.response_url,
    __retryCount:   loopItem.__retryCount,
    __maxRetries:   loopItem.__maxRetries,
    __retryDelaySec: loopItem.__retryDelaySec,

    // From poll
    status: pollResult.status || 'UNKNOWN',
    poll_detail: pollResult
  }
}];

// Flatten images[] AND re-attach shot identity so downstream
// nodes (upload, sheet update) always know which shot this is.
const context = $('if in progress?').item.json;  // has shot_num etc.
const responseData = $input.item.json;

const images = responseData.images || [];

return images.map((img, idx) => ({
  json: {
    // === Shot identity travels to upload nodes ===
    shot_num:     context.shot_num,
    shot_position: context.shot_position,
    reelNumber:   context.reelNumber,
    reelReviewId: context.reelReviewId,
    kling_prompt: context.kling_prompt,

    // === Image data ===
    image_index: idx,
    url:   img.url,
    width: img.width,
    height: img.height,
    content_type: img.content_type,

    // So downstream $json['0'].url still works if needed
    '0': { url: img.url }
  }
}));

// ❌ Dead-letter: shot timed out — log for manual retry
const item = $input.item.json;
return [{
  json: {
    type: 'TIMEOUT',
    shot_num:    item.shot_num,
    reelNumber:  item.reelNumber,
    request_id:  item.request_id,
    response_url: item.response_url,
    retries:     item.__retryCount,
    error:       `Shot ${item.shot_num} did not complete after ${item.__maxRetries} retries`,
    failedAt:    new Date().toISOString()
  }
}];

// ❌ Dead-letter: fal.ai never returned a request handle
const item = $input.item.json;
return [{
  json: {
    type:       'NO_HANDLE',
    shot_num:   item.shot_num,
    reelNumber: item.reelNumber,
    prompt:     item.kling_prompt,
    error:      item.__fal_error_msg,
    raw:        item.__fal_raw,
    failedAt:   new Date().toISOString()
  }
}];
